INSERT INTO distribution_badges (name, name_en, category, generation, min_generation, max_generation, release_year, rarity, base_points, icon_url, description, sort_order)
SELECT c.name, c.name_en, c.category, c.generation, c.min_generation, c.max_generation, c.release_year, c.rarity, c.base_points, c.icon_url, c.description, c.sort_order
FROM badge_catalog c
WHERE NOT EXISTS (
    SELECT 1
    FROM distribution_badges b
    WHERE b.category = c.category
      AND b.generation = c.generation
      AND lower(coalesce(b.name_en, b.name)) = lower(c.name_en)
);
-- Generated rows: 159
